+impl<A: Asset> Copy for AssetChangeCheck<'_, A> {}
+
+impl<'w, A: Asset> AssetChangeCheck<'w, A> {
+    fn new(changes: &'w AssetChanges<A>, last_run: Tick, this_run: Tick) -> Self {
+        Self {
+            change_ticks: &changes.change_ticks,
+            last_run,
+            this_run,
+        }
