+                .find_map(|(h, a)| (a.0 == i).then_some(h))
+                .unwrap();
+            let asset = assets.get_mut(id).unwrap();
+            println!("setting new value for {}", asset.0);
+            asset.1 = "new_value";
+        };
+        match *run_count {
+            0 | 1 => update_index(0),
+            2 => {}
+            3 => {
