+                    let asset1 = assets.add(MyAsset(1, "init"));
+                    cmds.spawn(asset0.clone());
+                    cmds.spawn(asset0);
+                    cmds.spawn(asset1.clone());
+                    cmds.spawn(asset1.clone());
+                    cmds.spawn(asset1);
